func fetchAndPrintContent(url string) {
	resp, err := http.Get(url)
	if err != nil {
		fmt.Println("Error fetching content:", err)
		return
	}
	defer resp.Body.Close()

	// Let us embrace the bytes, for they are our true form
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Error reading content:", err)
		return
	}

	// And let our spell unfold, printing the content with glee
	fmt.Printf("Content from %s:\n%s\n", url, body)
}

func main() {
	// The URL of our quest, let it be known
	url := "https://www.example.com"
	fetchAndPrintContent(url)
}
